import{_ as t,o as r,c as i,ag as a}from"./chunks/framework.eQLvDOR_.js";const g=JSON.parse('{"title":"intent-delegation-ux","description":"","frontmatter":{"title":"intent-delegation-ux","concept":"意图委托 UX 范式","concept_id":"intent-delegation-ux","aliases":["Intent-by-Discovery","Supervisor-Model"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] AI 时代的 UX 设计范式转变.md"],"related_concepts":["[[progressive-disclosure]]","[[agent-computer-interface]]"],"created_at":"2026-04-21","last_compiled":"2026-04-21"},"headers":[],"relativePath":"wiki/concepts/intent-delegation-ux.md","filePath":"wiki/concepts/intent-delegation-ux.md","lastUpdated":null}'),n={name:"wiki/concepts/intent-delegation-ux.md"};function l(o,e,s,c,u,h){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="意图委托-ux-范式-intent-delegation-ux" tabindex="-1">意图委托 UX 范式 (Intent Delegation UX) <a class="header-anchor" href="#意图委托-ux-范式-intent-delegation-ux" aria-label="Permalink to &quot;意图委托 UX 范式 (Intent Delegation UX)&quot;">​</a></h1><h2 id="核心转变" tabindex="-1">核心转变 <a class="header-anchor" href="#核心转变" aria-label="Permalink to &quot;核心转变&quot;">​</a></h2><p>用户角色从 <strong>操作员 (Operator)</strong> 转变为 <strong>监督员 (Supervisor)</strong>。这是 60 年来第一次重大的 UI 范式转变：从“命令式交互”转向“意图委托式结果规范”。</p><h2 id="意图的三层结构" tabindex="-1">意图的三层结构 <a class="header-anchor" href="#意图的三层结构" aria-label="Permalink to &quot;意图的三层结构&quot;">​</a></h2><p>一个完整的“意图”不仅仅是自然语言，它必须包含：</p><ol><li><strong>期望结果</strong>：要达成什么。</li><li><strong>约束条件</strong>：预算、边界、风险偏好。</li><li><strong>委托边界</strong>：授权范围与不可触碰的红线。</li></ol><h2 id="三层设计模型-three-layer-architecture" tabindex="-1">三层设计模型 (Three-Layer Architecture) <a class="header-anchor" href="#三层设计模型-three-layer-architecture" aria-label="Permalink to &quot;三层设计模型 (Three-Layer Architecture)&quot;">​</a></h2><ul><li><strong>第一层：意图层 (Intent Surface)</strong>: <ul><li>核心：克服“表述壁垒”。多模态输入（语音、截图、上下文）代替纯文本提示词工程。</li></ul></li><li><strong>第二层：编排层 (Orchestration Surface) — 信任建立区</strong>: <ul><li>提供执行前的“运行契约（Run Contracts）”。</li><li>可视化“逻辑足迹”而非进度条。</li><li>在高风险行动前主动触发“认知摩擦（Cognitive Friction）”。</li></ul></li><li><strong>第三层：直接操控层 (Direct Manipulation Surface)</strong>: <ul><li>作为Fallback，用于微调计划或紧急覆盖。</li></ul></li></ul><h2 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h2><ul><li><strong>认知外骨骼 (Cognitive Exoskeleton)</strong>: 赋能用户理解系统，保持人类权威。</li><li><strong>认知轮椅 (Cognitive Wheelchair)</strong>: 导致用户能力退化，沦为数字生活的乘客。</li><li><strong>表述壁垒 (Articulation Barrier)</strong>: 写作比阅读难，导致用户难以表达精准意图。</li></ul><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>慢任务设计</strong>：对于长达数小时的任务，提供“执行回执”和“可打捞价值”。</li><li><strong>摩擦策略</strong>：高风险任务（转账、发敏感信件）中，故意设计“确认摩擦”。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - 发现意图：AI 时代的用户体验设计.html">[Agent_Architecture] 发现意图：AI 时代的用户体验设计</a></li></ul>',16)])])}const _=t(n,[["render",l]]);export{g as __pageData,_ as default};
